spec = FileAttachment("charts/placeHolder.json").json()
vegaEmbed = require("vega-embed@6")
chart = {
  const el = document.querySelector("#chart");
  const result = await vegaEmbed(el, spec, {
    renderer: "svg",
    actions: false
  });
  return result.view;
}
scrollama_lib = require("scrollama")
scroller = {
  const s = scrollama_lib();
  s.setup({
    step: ".new-trigger",
    offset: 0.5
  }).onStepEnter(trigger =&gt; {
    console.log("step", trigger.index);
    if (trigger.index === 0) chart?.signal("highlight", null).run();
    if (trigger.index === 1) chart?.signal("highlight", "nc").run();
    if (trigger.index === 2) chart?.signal("highlight", "ci").run();
  });
  return s;
}

